    name: '黃啟倫',
    product: 'PFK', 
    fyp: '100,000',
    fyc: '35,000',
    date: new Date().toISOString().split('T')[0],
    image: null as string | null, 
    bgImage: DEFAULT_BG_URL,
  });

  // 響應式預覽縮放
  useEffect(() => {
