        pixelRatio: 2,
        backgroundColor: '#000',
        width: 480,
        height: 600,
        cacheBust: true,
        // 確保字體加載
        skipFonts: false,
      });

      setResultImageUrl(dataUrl);
      setShowResultModal(true);

      // 同時嘗試傳統下載（PC端有效）
      const link = document.createElement('a');
      link.download = `賀報_${data.name}.png`;
      link.href = dataUrl;
      link.click();

    } catch (e) {
      console.error(e);
      alert("產生失敗，請確認圖片載入正確或嘗試截圖。");
    } finally {
      setIsDownloading(false);
    }
  };

