import React, { useState, useRef, useEffect } from 'react';
import ReactDOM from 'react-dom/client';
import { Download, Gem, Calendar, Palette, Image as ImageIcon, X, Layout, Loader2, RefreshCw, CheckCircle2 } from 'lucide-react';
import { toPng } from 'html-to-image';

// --- Constants ---
const SHEET_CSV_URL = 'https://docs.google.com/spreadsheets/d/e/2PACX-1vTU3_CIpMZcKYy8HNwz7roxLlUM4ndzxn8AJvtD38IA-VsNykmY9wzU-fkEotDNyy1F955_toROJAy-/pub?output=csv';
const DEFAULT_BG_URL = 'https://lh3.googleusercontent.com/u/0/d/1AffsJ-awf6jfdme6nlFp4Y991gIA_rRm=w1600';

const AwardGenerator = () => {
  const [isDownloading, setIsDownloading] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [previewScale, setPreviewScale] = useState(1);
  const [showResultModal, setShowResultModal] = useState(false);
  const [resultImageUrl, setResultImageUrl] = useState<string | null>(null);

  const awardRef = useRef<HTMLDivElement>(null);
  const previewWrapperRef = useRef<HTMLDivElement>(null);

  const [data, setData] = useState({
    name: '黃啟倫',
    product: 'PFK', 
    fyp: '100,000',
    fyc: '35,000',
    date: new Date().toISOString().split('T')[0],
    image: null as string | null, // 這裡會存 Base64
    bgImage: null as string | null, // 這裡也會存 Base64
  });

  // 強大且穩定的圖片轉 Base64 工具 (帶有快取排除與 CORS 強制)
  const safeConvertToBase64 = async (url: string): Promise<string> => {
    if (!url) return '';
    if (url.startsWith('data:')) return url;

    try {
      // 增加快取排除參數，確保每次都拿新的 CORS Header
      const cacheBustUrl = `${url}${url.includes('?') ? '&' : '?'}cb=${Date.now()}`;
      const response = await fetch(cacheBustUrl, { 
        mode: 'cors',
        headers: { 'Cache-Control': 'no-cache' }
      });

      const blob = await response.blob();
      return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.onerror = reject;
        reader.readAsDataURL(blob);
      });
    } catch (e) {
      console.error("Critical: Base64 fetch failed:", e);
      return url; // 退而求其次回傳原網址，但這可能導致 Safari 變白
    }
  };

  // 初始化載入
  useEffect(() => {
    const init = async () => {
      const b64 = await safeConvertToBase64(DEFAULT_BG_URL);
      setData(prev => ({ ...prev, bgImage: b64 }));
    };
    init();
  }, []);

  // 響應式縮放
  useEffect(() => {
    const handleResize = () => {
      if (previewWrapperRef.current) {
        const containerWidth = previewWrapperRef.current.offsetWidth;
        const targetWidth = 480; 
        setPreviewScale(containerWidth < targetWidth + 40 ? (containerWidth - 40) / targetWidth : 1);
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize(); 
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const compressAndSetImage = (file: File, target: 'image' | 'bgImage') => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = (event) => {
      const img = new Image();
      img.src = event.target?.result as string;
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const MAX = target === 'bgImage' ? 1200 : 800;
        const scale = Math.min(1, MAX / Math.max(img.width, img.height));
        canvas.width = img.width * scale;
        canvas.height = img.height * scale;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(img, 0, 0, canvas.width, canvas.height);
        const b64 = canvas.toDataURL('image/jpeg', 0.85);
        setData(prev => ({ ...prev, [target]: b64 }));
      };
    };
  };

  const syncPhotoFromSheet = async () => {
    if (!data.name.trim()) return alert('請輸入姓名');
    setIsSyncing(true);
    try {
      const res = await fetch(`${SHEET_CSV_URL}&t=${Date.now()}`);
      const csvData = await res.text();
      const rows = csvData.split('\n').map(r => r.split(',').map(c => c.trim().replace(/"/g, '')));
      const target = rows.find(r => r.some(c => c === data.name));

      if (target) {
        const url = target.find(c => c.includes('drive.google.com'));
        if (url) {
          const id = url.includes('/d/') ? url.split('/d/')[1].split('/')[0] : url.split('id=')[1]?.split('&')[0];
          if (id) {
            const photoUrl = `https://lh3.googleusercontent.com/u/0/d/${id}=w1000`;
            // 重要：同步時就直接轉成 Base64
            const b64 = await safeConvertToBase64(photoUrl);
            setData(prev => ({ ...prev, image: b64 }));
          }
        } else {
          alert('找不到連結');
        }
      } else {
        alert('找不到此人');
      }
    } catch (e) {
      alert("同步失敗");
    } finally {
      setIsSyncing(false);
    }
  };

  const downloadImage = async () => {
    if (!awardRef.current || isDownloading) return;
    setIsDownloading(true);

    try {
      // 關鍵：等待所有圖片解碼完成
      const images = awardRef.current.querySelectorAll('img');
      await Promise.all(Array.from(images).map(img => {
        if (img.complete) return Promise.resolve();
        return img.decode().catch(() => {});
      }));

      // 等待微小的渲染穩定時間
      await new Promise(r => setTimeout(r, 200));

      const dataUrl = await toPng(awardRef.current, {
        pixelRatio: 2,
        backgroundColor: '#000',
        width: 480,
        height: 600,
        cacheBust: true,
        skipFonts: false,
      });

      setResultImageUrl(dataUrl);
      setShowResultModal(true);

      // PC 端嘗試自動下載
      const link = document.createElement('a');
      link.download = `賀報_${data.name}.png`;
      link.href = dataUrl;
      link.click();

    } catch (e) {
      console.error(e);
      alert("生成失敗，請嘗試手動截圖。");
    } finally {
      setIsDownloading(false);
    }
  };

  const getFontSize = (str: string) => {
    const len = str?.toString().length || 0;
    return len > 10 ? 'text-2xl' : len > 7 ? 'text-3xl' : 'text-4xl';
  };

  return (
    <div className="min-h-screen p-4 md:p-8 font-sans text-slate-200 bg-slate-900">

      {/* 下載結果彈窗 - 針對 iPhone 最佳化 */}
      {showResultModal && resultImageUrl && (
        <div className="fixed inset-0 z-[100] flex flex-col items-center justify-center p-4 bg-slate-950/98 backdrop-blur-xl animate-in fade-in duration-300">
          <button 
            onClick={() => setShowResultModal(false)}
            className="absolute top-6 right-6 p-2 bg-white/10 hover:bg-white/20 rounded-full text-white transition-all active:scale-90"
          >
            <X className="w-8 h-8" />
          </button>

          <div className="text-center mb-6">
            <div className="flex items-center justify-center gap-2 mb-2">
              <CheckCircle2 className="w-6 h-6 text-green-500" />
              <h3 className="text-xl font-bold text-white">賀報製作完成</h3>
            </div>
            <p className="text-slate-400 text-sm">請「長按下方圖片」儲存至手機相簿</p>
          </div>

          <div className="relative max-w-full max-h-[70vh] shadow-[0_20px_50px_rgba(0,0,0,0.5)] rounded-xl overflow-hidden border border-white/10">
            {/* 加入防止 iOS 攔截的 Style */}
            <img 
              src={resultImageUrl} 
              className="max-w-full max-h-[70vh] object-contain block select-auto pointer-events-auto"
              style={{ WebkitTouchCallout: 'default' } as any}
              alt="Generated Award"
              onContextMenu={(e) => e.stopPropagation()}
            />
          </div>

          <button 
            onClick={() => setShowResultModal(false)}
            className="mt-8 px-12 py-4 bg-white text-slate-900 rounded-full font-black text-lg shadow-xl active:scale-95 transition-all"
          >
            返回修改
          </button>
        </div>
      )}

      <div className="max-w-6xl mx-auto grid grid-cols-1 md:grid-cols-12 gap-8">
        {/* 控制面板 */}
        <div className="md:col-span-4 space-y-5 order-2 md:order-1">
          <div className="bg-slate-800 border border-slate-700 rounded-xl p-6 shadow-2xl">
            <div className="flex items-center justify-between mb-6">
              <div>
                <h1 className="text-xl font-bold text-white flex items-center gap-2">
                  <Palette className="w-6 h-6 text-red-500" /> 中恩賀報 Pro
                </h1>
                <p className="text-slate-500 text-[9px] tracking-widest uppercase">Premium Edition v2.1</p>
              </div>
              <div className="bg-red-500/10 text-red-500 px-2 py-1 rounded text-[10px] font-bold border border-red-500/20">iOS FIX</div>
            </div>

            <div className="space-y-4">
              <div className="group">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1 block group-focus-within:text-red-500 transition-colors">姓名</label>
                <div className="flex gap-2">
                  <input type="text" value={data.name} onChange={e => setData({...data, name: e.target.value})} className="flex-1 bg-slate-900 border border-slate-600 rounded-lg p-3 text-white focus:border-red-500 outline-none transition-all" placeholder="輸入姓名" />
                  <button onClick={syncPhotoFromSheet} disabled={isSyncing} className="bg-slate-700 hover:bg-slate-600 px-4 rounded-lg transition-colors disabled:opacity-50">
                    {isSyncing ? <Loader2 className="w-5 h-5 animate-spin text-white" /> : <RefreshCw className="w-5 h-5 text-white" />}
                  </button>
                </div>
              </div>

              <div>
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1 block">成交商品</label>
                <input type="text" value={data.product} onChange={e => setData({...data, product: e.target.value})} className="w-full bg-slate-900 border border-slate-600 rounded-lg p-3 text-white focus:border-red-500 outline-none" />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1 block">FYP</label>
                  <input type="text" value={data.fyp} onChange={e => setData({...data, fyp: e.target.value})} className="w-full bg-slate-900 border border-slate-600 rounded-lg p-3 text-white font-mono" />
                </div>
                <div>
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1 block">FYC</label>
                  <input type="text" value={data.fyc} onChange={e => setData({...data, fyc: e.target.value})} className="w-full bg-slate-900 border border-slate-600 rounded-lg p-3 text-white font-mono" />
                </div>
              </div>

              <div>
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1 block">報件日期</label>
                <input type="date" value={data.date} onChange={e => setData({...data, date: e.target.value})} className="w-full bg-slate-900 border border-slate-600 rounded-lg p-3 text-white" />
              </div>

              <div className="grid grid-cols-2 gap-3 pt-2">
                <label className="flex flex-col items-center justify-center h-20 border-2 border-slate-600 border-dashed rounded-xl cursor-pointer hover:bg-slate-700 transition-colors bg-slate-900/50">
                  <ImageIcon className="w-5 h-5 text-slate-500 mb-1" />
                  <span className="text-[9px] font-bold text-slate-400 text-center uppercase tracking-tighter">更換底圖</span>
                  <input type="file" className="hidden" accept="image/*" onChange={e => {
                    const file = (e.target as HTMLInputElement).files?.[0];
                    if (file) compressAndSetImage(file, 'bgImage');
                  }} />
                </label>
                <label className="flex flex-col items-center justify-center h-20 border-2 border-slate-600 border-dashed rounded-xl cursor-pointer hover:bg-slate-700 transition-colors bg-slate-900/50">
                  <ImageIcon className="w-5 h-5 text-slate-500 mb-1" />
                  <span className="text-[9px] font-bold text-slate-400 text-center uppercase tracking-tighter">手動人像</span>
                  <input type="file" className="hidden" accept="image/*" onChange={e => {
                    const file = (e.target as HTMLInputElement).files?.[0];
                    if (file) compressAndSetImage(file, 'image');
                  }} />
                </label>
              </div>
            </div>

            <div className="mt-8 pt-6 border-t border-slate-700">
               <button onClick={downloadImage} disabled={isDownloading || !data.bgImage} className={`w-full ${isDownloading ? 'bg-slate-600' : 'bg-red-600 hover:bg-red-500'} text-white font-black py-4 rounded-xl shadow-xl flex items-center justify-center gap-2 transition-all active:scale-95 text-lg`}>
                 {isDownloading ? <Loader2 className="w-6 h-6 animate-spin" /> : <Download className="w-6 h-6" />}
                 {isDownloading ? '處理中...' : '生成高清圖檔'}
               </button>
               <div className="mt-4 flex items-center justify-center gap-4">
                 <div className="flex items-center gap-1">
                   <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
                   <span className="text-[8px] text-slate-500 font-bold uppercase">Base64 Ready</span>
                 </div>
                 <div className="flex items-center gap-1">
                   <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
                   <span className="text-[8px] text-slate-500 font-bold uppercase">CORS Secured</span>
                 </div>
               </div>
            </div>
          </div>
        </div>

        {/* 預覽區 */}
        <div ref={previewWrapperRef} className="md:col-span-8 flex flex-col items-center justify-start min-h-[650px] order-1 md:order-2">
          <div 
            style={{ 
              transform: `scale(${previewScale})`, 
              transformOrigin: 'top center', 
              width: '480px', 
              height: '600px', 
              marginBottom: `${(600 * previewScale) - 600}px` 
            }}
            className="relative overflow-hidden shadow-[0_40px_100px_rgba(0,0,0,0.6)] bg-black shrink-0 rounded-sm"
          >
            <div ref={awardRef} className="w-full h-full relative bg-black">
                {/* 背景底圖 */}
                <div className="absolute inset-0 z-0 bg-neutral-900">
                  {data.bgImage && (
                    <img src={data.bgImage} className="w-full h-full object-cover" alt="bg" />
                  )}
                </div>

                {/* 裝飾框 */}
                <div className="absolute inset-4 z-10 pointer-events-none border border-white/20">
                  <div className="absolute top-0 left-0 w-10 h-10 border-t-2 border-l-2 border-white/40"></div>
                  <div className="absolute top-0 right-0 w-10 h-10 border-t-2 border-r-2 border-white/40"></div>
                  <div className="absolute bottom-0 left-0 w-10 h-10 border-b-2 border-l-2 border-white/40"></div>
                  <div className="absolute bottom-0 right-0 w-10 h-10 border-b-2 border-r-2 border-white/40"></div>
