                {/* 內容區 */}
                <div className="absolute inset-0 z-20 flex flex-col items-center pt-14 pb-8 px-8 text-center">

                  {/* 人像 */}
                  <div className="relative w-52 h-52 mb-4 shrink-0">
                    <div className="absolute inset-[-15px] rounded-full bg-gradient-to-b from-black/0 to-black/40 blur-3xl opacity-60"></div>
                    <div className="relative w-full h-full rounded-full overflow-hidden bg-neutral-800 flex items-center justify-center border-4 border-white/10 shadow-2xl">
                      {data.image ? (
                        <img src={data.image} className="w-full h-full object-cover" alt="avatar" />
                      ) : (
                        <span className="text-[10rem] font-black font-serif-tc text-white/5">賀</span>
                      )}
                    </div>
                  </div>

                  {/* 姓名 */}
                  <h2 className="text-5xl font-black text-white tracking-[0.15em] drop-shadow-[0_4px_15px_rgba(0,0,0,0.9)] font-serif-tc mb-4 shrink-0 leading-tight">
