                  {/* 頁尾 */}
                  <div className="mt-auto flex flex-col items-center gap-1.5 opacity-90 shrink-0">
                    <div className="flex items-center gap-3">
                      <span className="text-[11px] font-black tracking-[0.2em] text-white drop-shadow-sm">B1690</span>
                      <span className="text-white/20">|</span>
                      <span className="text-[11px] font-black tracking-[0.3em] text-white drop-shadow-sm">中恩通訊處</span>
                    </div>
                    <div className="flex items-center gap-2 text-white/80 font-mono text-xs tracking-[0.2em] drop-shadow-sm uppercase">
                      <Calendar className="w-3.5 h-3.5 opacity-60" />
                      {data.date.replace(/-/g, '.')}
                    </div>
                  </div>
                </div>
            </div>
          </div>
          <p className="text-slate-500 text-[10px] mt-6 tracking-widest uppercase font-bold opacity-50">High Resolution Template (480x600)</p>
        </div>
      </div>
    </div>
  );
};

